union SCommandHeader
{
	struct
	{
		uint32_t bugus : 4;// >> 0
		uint32_t mission : 2; // >> 4
		uint32_t order : 10; // >> 6
		uint32_t extra : 8; // >> 16
		uint32_t option : 8; // >> 24
	};
	uint32_t data;

	SCommandHeader()
	{
		memset(this, 0, sizeof(SCommandHeader));
	}

	SCommandHeader(uint32_t data)
	{
		memset(this, 0, sizeof(SCommandHeader));
		this->data = data;
	}
};

