inline void* nocrt_memset(void* ptr, int value, std::size_t num) 
{
	unsigned char* pdst = (unsigned char*)ptr;
	while (num--) *(pdst++) = (unsigned char)value;
	return ptr;
}


inline void* nocrt_memcpy(void* dst, const void* src, size_t num)
{
	if (num % sizeof(long) == 0)
	{
		num /= sizeof(long);
		unsigned long* pdst32 = static_cast<unsigned long*>(dst);
		const unsigned long* psrc32 = static_cast<const unsigned long*>(src);

		while (num--) *(pdst32++) = *(psrc32++);
	}
	else
	{
		unsigned char* pdst = static_cast<unsigned char*>(dst);
		const unsigned char* psrc = static_cast<const unsigned char*>(src);

		while (num--) *(pdst++) = *(psrc++);
	}

	return dst;
}


inline size_t nocrt_strlen(const char* s)
{
	const char* ptr = s;
	while (*ptr != '\0') ptr++;
	return ptr - s;
}

inline char* nocrt_strcpy(char* dst, const char* src)
{
	char* pdst = dst;

	while (*src != '\0')
	{
		*pdst = *src;
		src++;
		pdst++;
	}

	*pdst = '\0';

	return dst;
}

class old_string {
public:
	std::uint32_t pad;
	union {
		char* str;
		char shortstr[16];
	} bx;
	std::size_t size;
	std::size_t capacity;
	old_string& operator=(const char* newStr)
	{
		std::size_t newLength = nocrt_strlen(newStr);

		if (newLength <= 15)
		{
			nocrt_memcpy(bx.shortstr, newStr, newLength + 1);
			size = newLength;
			capacity = 15;
		}
		else
		{
			if (newLength <= capacity)
				nocrt_memcpy(bx.str, newStr, newLength + 1);
			else
			{
				delete[] bx.str;
				bx.str = new char[newLength + 1];
				nocrt_strcpy(bx.str, newStr);
				capacity = newLength;
			}
			size = newLength;
		}
		return *this;
	}
};

