class pointer_encryption
{
private:
	__forceinline int gen_random_int(int min, int max)
	{
		static std::mt19937 engine(std::random_device{}());
		std::uniform_int_distribution<int> dist(min, max);
		return dist(engine);
	}

	__forceinline int* get_random_array()
	{
		static int random[12];
		static bool init = false;

		if (!init)
		{
			for (int i = 0; i < sizeof(random) / sizeof(std::uintptr_t); i++)
			{
				random[i] = gen_random_int(0xFFF, 0xFFFFFF);
			}

			init = true;
		}

		return random;
	}

	__forceinline void* get_base()
	{
		static void* base = (void*)GetModuleHandleA(nullptr);
		return base;
	}

	__forceinline void* get_peb()
	{
#ifdef _WIN64
		static void* peb = (void*)__readgsqword(0x60);
#else
		static void* peb = (void*)__readfsdword(0x30);
#endif
		return peb;
	}

	__forceinline void* get_instance()
	{
		static void* instance = this;
		return instance;
	}

public:
	template <typename t>
	__forceinline t process(void* in_ptr)
	{
		std::uintptr_t ptr_address = (std::uintptr_t)in_ptr;

		std::uintptr_t key_array[18];
		key_array[0] = 0xC7FA8EF6;
		key_array[1] = (std::uintptr_t)get_instance();
		key_array[2] = 0xA9F6EFC2 + static_cast<int>(__DATE__[0]) + static_cast<int>(__DATE__[1]) + static_cast<int>(__DATE__[2]);
		key_array[3] = (std::uintptr_t)get_base();
		key_array[4] = 0x5A98F6C1;
		key_array[5] = (std::uintptr_t)get_peb();
		key_array[6] = 0x6C9F5E8A;
		key_array[7] = 0xFB38B773 + static_cast<int>(__TIMESTAMP__[0]) + static_cast<int>(__TIMESTAMP__[1]) + static_cast<int>(__TIMESTAMP__[2]);
		key_array[8] = (std::uintptr_t)get_base() ^ (std::uintptr_t)get_peb();
		key_array[9] = 0x5216D58A;
		key_array[10] = 0xECDF0931;
		key_array[11] = 0x5DA5FCEF;
		key_array[12] = (std::uintptr_t)get_instance() ^ (std::uintptr_t)get_base();
		key_array[13] = 0x95ACF30D + static_cast<int>(__TIMESTAMP__[11]) + static_cast<int>(__TIMESTAMP__[12]) + static_cast<int>(__TIMESTAMP__[14]);
		key_array[14] = 0x2E2CDFE2;
		key_array[15] = 0x824E7BD4;
		key_array[16] = (std::uintptr_t)get_instance() ^ (std::uintptr_t)get_peb();
		key_array[17] = 0x4D703C6C + static_cast<int>(__TIMESTAMP__[15]) + static_cast<int>(__TIMESTAMP__[17]) + static_cast<int>(__TIMESTAMP__[18]);

		for (int i = 0; i < sizeof(key_array) / sizeof(std::uintptr_t); i++)
		{
			if (i < 12)
			{
				static int* random = get_random_array();
				if (random)
					key_array[i] ^= random[i];
			}

			key_array[i] ^= (~(i % 2) ^ (i + 1) * (i + 1) >> 0xC) | 0xF;
			key_array[i] += ((i + 1) * 0xC6A) ^ 0xCF6A9F;
			key_array[i] <<= 0xC;
			key_array[i] -= 0x7F9A ^ (~(i % 2) * (i + 1)) | 0xA;
			key_array[i] *= ((i + i) * i) + 0x76A;
			key_array[i] ^= _byteswap_ulong(0xC5A9E6A1);
			key_array[i] >>= 0xC;

			key_array[i] *= (~(i % 4) ^ (i + 0xC) * (i + 0xA) >> 0xFF) | 0xA;
			key_array[i] -= ((i * 4) * 0x5A8E) ^ 0xA5E89F;
			key_array[i] <<= 0xA;
			key_array[i] ^= 0xC63EA ^ (~(i % 3) * (i + 4)) | 0xC;
			key_array[i] *= ((i + i) * i) + 0xCF;
			key_array[i] += _byteswap_ulong(0x6F9A5EC1);
			key_array[i] >>= 0xF;

			bool should_decrypt = ptr_address & 0x80000000000;

			if (should_decrypt)
			{
				ptr_address &= ~(0x80000000000);
				ptr_address ^= key_array[i];
			}
			else
			{
				ptr_address |= 0x80000000000;
				ptr_address ^= key_array[i];
			}
		}

		return (t)ptr_address;
	}
};

inline pointer_encryption* g_ptr = new pointer_encryption();
#define PROCESS_PTR(type, ptr, decrypt) g_ptr->process<type>(ptr, decrypt)
#define PROCESS_PTR_AUTO(ptr, decrypt) g_ptr->process<decltype(ptr)>(ptr, decrypt)


class enc_ptr
{
private:
	std::uintptr_t encrypted_ptr;
	__forceinline constexpr std::uintptr_t byteswap(std::uintptr_t value)
	{
		return ((value & 0xFF000000) >> 24) |
			((value & 0x00FF0000) >> 8) |
			((value & 0x0000FF00) << 8) |
			((value & 0x000000FF) << 24);
	}

	__forceinline constexpr std::uintptr_t date_key()
	{
		return static_cast<int>(__DATE__[0]) +
			static_cast<int>(__DATE__[1]) +
			static_cast<int>(__DATE__[2]);
	}

	__forceinline constexpr std::uintptr_t timestamp_1_key()
	{
		return static_cast<int>(__TIMESTAMP__[0]) +
			static_cast<int>(__TIMESTAMP__[1]) +
			static_cast<int>(__TIMESTAMP__[2]);
	}

	__forceinline constexpr std::uintptr_t timestamp_2_key()
	{
		return static_cast<int>(__TIMESTAMP__[11]) +
			static_cast<int>(__TIMESTAMP__[12]) +
			static_cast<int>(__TIMESTAMP__[14]);
	}

	__forceinline constexpr std::uintptr_t timestamp_3_key()
	{
		return static_cast<int>(__TIMESTAMP__[15]) +
			static_cast<int>(__TIMESTAMP__[17]) +
			static_cast<int>(__TIMESTAMP__[18]);
	}
	__forceinline std::uintptr_t process(std::uintptr_t in_ptr)
	{
		std::uintptr_t ptr_address = in_ptr;

		std::uintptr_t key_array[18] = {
			0xC7FA8EF6 + timestamp_1_key(),
			0xCAFEBABE,
			0xA9F6EFC2 + date_key(),
			0xDEADBEEF,
			0x5A98F6C1 + timestamp_3_key(),
			0xBAADF00D,
			0x6C9F5E8A + date_key(),
			0xFB38B773,
			0xFB38B773 + timestamp_1_key(),
			0x5216D58A,
			0xECDF0931 + date_key(),
			0x5DA5FCEF,
			0xFEEDFACE,
			0x95ACF30D + timestamp_2_key(),
			0x2E2CDFE2,
			0x824E7BD4 + date_key(),
			0xD15EA5E,
			0x4D703C6C + timestamp_3_key()
		};


		for (int i = 0; i < sizeof(key_array) / sizeof(std::uintptr_t); i++)
		{
			key_array[i] ^= (~(i % 2) ^ (i + 1) * (i + 1) >> 0xC) | 0xF;
			key_array[i] += ((i + 1) * 0xC6A) ^ 0xCF6A9F;
			key_array[i] <<= 0xC;
			key_array[i] -= 0x7F9A ^ (~(i % 2) * (i + 1)) | 0xA;
			key_array[i] *= ((i + i) * i) + 0x76A;
			key_array[i] ^= byteswap(0xC5A9E6A1);
			key_array[i] >>= 0xC;

			key_array[i] *= (~(i % 4) ^ (i + 0xC) * (i + 0xA) >> 0xFF) | 0xA;
			key_array[i] -= ((i * 4) * 0x5A8E) ^ 0xA5E89F;
			key_array[i] <<= 0xA;
			key_array[i] ^= 0xC63EA ^ (~(i % 3) * (i + 4)) | 0xC;
			key_array[i] *= ((i + i) * i) + 0xCF;
			key_array[i] += byteswap(0x6F9A5EC1);
			key_array[i] >>= 0xF;

			bool should_decrypt = ptr_address & 0x80000000000;

			if (should_decrypt)
			{
				ptr_address &= ~(0x80000000000);
				ptr_address ^= key_array[i];
			}
			else
			{
				ptr_address |= 0x80000000000;
				ptr_address ^= key_array[i];
			}
		}
		return ptr_address;
	}
public:

	enc_ptr(std::uintptr_t ptr)
	{
		std::uintptr_t ptr_address = ptr;

		std::uintptr_t key_array[18] = {
			0xC7FA8EF6 + timestamp_1_key(),
			0xCAFEBABE,
			0xA9F6EFC2 + date_key(),
			0xDEADBEEF,
			0x5A98F6C1 + timestamp_3_key(),
			0xBAADF00D,
			0x6C9F5E8A + date_key(),
			0xFB38B773,
			0xFB38B773 + timestamp_1_key(),
			0x5216D58A,
			0xECDF0931 + date_key(),
			0x5DA5FCEF,
			0xFEEDFACE,
			0x95ACF30D + timestamp_2_key(),
			0x2E2CDFE2,
			0x824E7BD4 + date_key(),
			0xD15EA5E,
			0x4D703C6C + timestamp_3_key()
		};


		for (int i = 0; i < sizeof(key_array) / sizeof(std::uintptr_t); i++)
		{

			key_array[i] ^= (~(i % 2) ^ (i + 1) * (i + 1) >> 0xC) | 0xF;
			key_array[i] += ((i + 1) * 0xC6A) ^ 0xCF6A9F;
			key_array[i] <<= 0xC;
			key_array[i] -= 0x7F9A ^ (~(i % 2) * (i + 1)) | 0xA;
			key_array[i] *= ((i + i) * i) + 0x76A;
			key_array[i] ^= byteswap(0xC5A9E6A1);
			key_array[i] >>= 0xC;

			key_array[i] *= (~(i % 4) ^ (i + 0xC) * (i + 0xA) >> 0xFF) | 0xA;
			key_array[i] -= ((i * 4) * 0x5A8E) ^ 0xA5E89F;
			key_array[i] <<= 0xA;
			key_array[i] ^= 0xC63EA ^ (~(i % 3) * (i + 4)) | 0xC;
			key_array[i] *= ((i + i) * i) + 0xCF;
			key_array[i] += byteswap(0x6F9A5EC1);
			key_array[i] >>= 0xF;

			bool should_decrypt = ptr_address & 0x80000000000;

			if (should_decrypt)
			{
				ptr_address &= ~(0x80000000000);
				ptr_address ^= key_array[i];
			}
			else
			{
				ptr_address |= 0x80000000000;
				ptr_address ^= key_array[i];
			}
		}
		encrypted_ptr = ptr_address;
	}

	__forceinline std::uintptr_t get()
	{
		std::uintptr_t decrypted_value = process(encrypted_ptr);
		encrypted_ptr = process(decrypted_value); 
		return decrypted_value;
	}
	__forceinline std::uintptr_t operator*() { return get(); }
	__forceinline std::uintptr_t operator->() { return get(); }
	__forceinline operator std::uintptr_t() { return get(); }

	__forceinline void set(std::uintptr_t new_ptr)
	{
		encrypted_ptr = process(new_ptr);
	}
};



class SwapAddressPatch
{
public:
	SwapAddressPatch() = default;

	template <typename T>
	bool Patch(std::uintptr_t targetAddress, T* newValue, const std::uint32_t startOffs = 2)
	{
		start_offset = startOffs;
		m_targetAddress = reinterpret_cast<void*>(targetAddress);
		if (!m_targetAddress) return false;

		auto newValueAddress = reinterpret_cast<std::uintptr_t>(newValue);
		DWORD oldProtect;
		

		if (!VirtualProtect(m_targetAddress, start_offset + sizeof(std::uintptr_t), PAGE_EXECUTE_READWRITE, &oldProtect)) return false;
		m_originalBytes.resize(sizeof(std::uintptr_t));
		nocrt_memcpy(m_originalBytes.data(), m_targetAddress, m_originalBytes.size());
		*reinterpret_cast<std::uintptr_t*>(reinterpret_cast<std::uintptr_t>(m_targetAddress) + start_offset) = newValueAddress;
		VirtualProtect(m_targetAddress, start_offset + sizeof(std::uintptr_t), oldProtect, &oldProtect);
		return true;
	}

	bool Unpatch()
	{
		if (!m_targetAddress || m_originalBytes.empty()) return false;
		DWORD oldProtect;
		if (!VirtualProtect(m_targetAddress, start_offset + m_originalBytes.size(), PAGE_EXECUTE_READWRITE, &oldProtect)) return false;
		nocrt_memcpy(m_targetAddress, m_originalBytes.data(), m_originalBytes.size());
		VirtualProtect(m_targetAddress, start_offset + m_originalBytes.size(), oldProtect, &oldProtect);
		return true;
	}

private:
	void* m_targetAddress = nullptr;
	std::uint32_t start_offset = 2;
	std::vector<std::uint8_t> m_originalBytes;
};

class PatchBytes
{
public:
	PatchBytes() = default;

	bool Patch(std::uintptr_t targetAddress, const void* newBytes, std::size_t size, std::uint32_t startOffs = 0)
	{
		if (!targetAddress || !newBytes || size == 0) return false;

		m_targetAddress = reinterpret_cast<void*>(targetAddress + startOffs);
		m_patchSize = size;

		DWORD oldProtect;
		if (!VirtualProtect(m_targetAddress, size, PAGE_EXECUTE_READWRITE, &oldProtect)) return false;
		m_originalBytes.resize(size);
		nocrt_memcpy(m_originalBytes.data(), m_targetAddress, size);
		nocrt_memcpy(m_targetAddress, newBytes, size);

		VirtualProtect(m_targetAddress, size, oldProtect, &oldProtect);
		return true;
	}

	bool Patch(std::uintptr_t targetAddress, const char* newBytes, std::size_t size, std::uint32_t startOffs = 0)
	{
		return Patch(targetAddress, static_cast<const void*>(newBytes), size, startOffs);
	}

	bool Unpatch()
	{
		if (!m_targetAddress || m_originalBytes.empty()) return false;

		DWORD oldProtect;
		if (!VirtualProtect(m_targetAddress, m_patchSize, PAGE_EXECUTE_READWRITE, &oldProtect)) return false;

		nocrt_memcpy(m_targetAddress, m_originalBytes.data(), m_patchSize);

		VirtualProtect(m_targetAddress, m_patchSize, oldProtect, &oldProtect);
		return true;
	}

private:
	void* m_targetAddress = nullptr;
	std::vector<std::uint8_t> m_originalBytes;
	std::size_t m_patchSize = 0;
};

template <typename FuncPtr, typename... Args>
inline auto _call(std::uintptr_t address, Args... args)
{
	return reinterpret_cast<FuncPtr>(address)(std::forward<Args>(args)...);
}
template <typename T>
inline T _rv(std::uintptr_t base, std::ptrdiff_t offset = 0)
{
	return *reinterpret_cast<T*>(base + offset);
}

template <typename T>
inline void _wv(std::uintptr_t base, std::ptrdiff_t offset, T value)
{
	*reinterpret_cast<T*>(base + offset) = value;
}

