		inline void SendPacket(char* data, int size = 0)
		{
			using tSendPacket = std::uint32_t(__thiscall*)(std::uint32_t*, char*, int);
			static auto oSendpacket = reinterpret_cast<tSendPacket>(Addresses::Hooks::Anticheat::GameManagers::NetMgr::SendPacket.get());

			using tGetMgr = std::uint32_t* (__cdecl*)();
			static auto GetNetMgr = reinterpret_cast<tGetMgr>(Addresses::Hooks::Anticheat::GameManagers::NetMgr::Get.get());

			if (GetNetMgr())
				oSendpacket(GetNetMgr(), data, size);
		}
		


		[[clang::annotate("x-vm,x-full,x-cfg,ind-br,alias-access,custom-cc")]]
		inline bool InitializeDllRegion(HMODULE hModule) 
		{
            auto current_proc = GetCurrentProcess();

			MODULEINFO anticheatModInfo = {};
			if (!GetModuleInformation(current_proc, hModule, &anticheatModInfo, sizeof(anticheatModInfo)))
				return false;

			g_AntiCheatModuleBase = reinterpret_cast<std::uint32_t>(anticheatModInfo.lpBaseOfDll);
			g_AntiCheatModuleSize = static_cast<std::uint32_t>(anticheatModInfo.SizeOfImage);
			//MegaGuard::EventLog->Debug(nostd::source_location::current(), "AntiCheat Module Base: 0x{:08X}, Size: 0x{:08X}", g_AntiCheatModuleBase, g_AntiCheatModuleSize);

			auto hGameModule = GetModuleHandleA(NULL);

			if (!hGameModule)
				return false;

			MODULEINFO gameModInfo = {};
			if (!GetModuleInformation(current_proc, hGameModule, &gameModInfo, sizeof(gameModInfo)))
				return false;

			g_GameModuleBase = reinterpret_cast<std::uint32_t>(gameModInfo.lpBaseOfDll);
			g_GameModuleSize = static_cast<std::uint32_t>(gameModInfo.SizeOfImage);
			//MegaGuard::EventLog->Debug(nostd::source_location::current(), "Game Module Base: 0x{:08X}, Size: 0x{:08X}", g_GameModuleBase, g_GameModuleSize);
			
			return true;
		}
